function withLogger(WrappedComponent) {
  function Enhanced(props) {
    useEffect(() => {
      console.log("Rendered:", WrappedComponent.name, props);
    });
    return <WrappedComponent {...props} />;
  }
  Enhanced.displayName = `withLogger(${getDisplayName(WrappedComponent)})`;
  return Enhanced;
}

const LoggedButton = withLogger(Button);

function withAuth(WrappedComponent) {
  function Enhanced(props) {
    const { user, loading } = useAuth();
    if (loading) return <Spinner />;
    if (!user) return <Navigate to="/login" />;
    return <WrappedComponent user={user} {...props} />;
  }
  return Enhanced;
}

const ProtectedDashboard = withAuth(Dashboard);

// Usage in router:
<Route path="/dashboard" element={<ProtectedDashboard />} />

function withData(fetchFn, dataProp = "data") {
  return function(WrappedComponent) {
    function Enhanced(props) {
      const [data, setData] = useState(null);
      const [loading, setLoading] = useState(true);
      useEffect(() => {
        setLoading(true);
        fetchFn(props).then((result) => {
          setData(result);
          setLoading(false);
        });
      }, []);
      const injected = { [dataProp]: data, loading };
      return <WrappedComponent {...props} {...injected} />;
    }
    return Enhanced;
  };
}

const UserProfileWithData = withData(fetchUser, "user")(UserProfile);
